#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=17,Mod=998244353,Inv2=499122177;int a[1<<17],b[1<<17],n,c[1<<17],A[1<<17],B[1<<17];
inline void DN(int &x){x>=Mod?x-=Mod:0;}inline void UP(int &x){x<0?x+=Mod:0;}
inline void FMTor (int *a){for(int i=0;i<n;++i)for(int S=0;S<(1<<n);++S)if((S>>i)&1)DN(a[S]+=a[S^(1<<i)]);}
inline void FMTand(int *a){for(int i=0;i<n;++i)for(int S=0;S<(1<<n);++S)if((S>>i)&1)DN(a[S^(1<<i)]+=a[S]);}
inline void IFMTor (int *a){for(int i=0;i<n;++i)for(int S=0;S<(1<<n);++S)if((S>>i)&1)UP(a[S]-=a[S^(1<<i)]);}
inline void IFMTand(int *a){for(int i=0;i<n;++i)for(int S=0;S<(1<<n);++S)if((S>>i)&1)UP(a[S^(1<<i)]-=a[S]);}
inline void FWT(int *a)
{
	for(int S=1;S<(1<<n);S<<=1)
		for(int T=0;T<(1<<n);T+=(S<<1))
			for(int Q=0;Q<S;++Q) {int x=a[T+Q],y=a[S+T+Q];DN(a[T+Q]=x+y);UP(a[S+T+Q]=x-y);}
}
inline void IFWT(int *a)
{
	for(int S=1;S<(1<<n);S<<=1)
		for(int T=0;T<(1<<n);T+=(S<<1))
			for(int Q=0;Q<S;++Q) {int x=a[T+Q],y=a[S+T+Q];a[T+Q]=1ll*(x+y)*Inv2%Mod;a[S+T+Q]=1ll*(x-y+Mod)*Inv2%Mod;}
}
inline void CNTor(int *a,int *b){FMTor(a);FMTor(b);for(int S=0;S<(1<<n);++S)c[S]=1ll*a[S]*b[S]%Mod;IFMTor(c);}
inline void CNTand(int *a,int *b){FMTand(a);FMTand(b);for(int S=0;S<(1<<n);++S)c[S]=1ll*a[S]*b[S]%Mod;IFMTand(c);}
inline void CNTxor(int *a,int *b){FWT(a);FWT(b);for(int S=0;S<(1<<n);++S)c[S]=1ll*a[S]*b[S]%Mod;IFWT(c);}
int main()
{
	n=read();
	for(int i=0;i<(1<<n);++i)DN(a[i]=read());
	for(int i=0;i<(1<<n);++i)DN(b[i]=read());
	memcpy(A,a,(1<<n)<<2);memcpy(B,b,(1<<n)<<2);
	CNTor(A,B); for(int i=0;i<(1<<n);++i)printf("%d ",c[i]);putchar('\n');
	memcpy(A,a,(1<<n)<<2);memcpy(B,b,(1<<n)<<2);
	CNTand(A,B);for(int i=0;i<(1<<n);++i)printf("%d ",c[i]);putchar('\n');
	memcpy(A,a,(1<<n)<<2);memcpy(B,b,(1<<n)<<2);
	CNTxor(A,B);for(int i=0;i<(1<<n);++i)printf("%d ",c[i]);putchar('\n');
}
